import React from 'react';
import { useWebSocket } from '../hooks/useWebSocket';

const DashboardOverview = () => {
    const { data } = useWebSocket("ws://localhost:8000/ws");

    if (!data) return null;

    return (
        <div className="space-y-6">
            <div className="flex flex-col">
                <span className="nothing-text-label mb-1">Active Agents</span>
                <div className="flex items-baseline space-x-2">
                    <span className="nothing-text-value text-white">{data.current_metrics.active_agents}</span>
                    <span className="text-[10px] text-gray-500 font-bold">READY</span>
                </div>
            </div>

            <div className="flex flex-col">
                <span className="nothing-text-label mb-1">System Load</span>
                <div className="flex items-baseline space-x-2">
                    <span className="nothing-text-value text-white">{data.current_metrics.db_load}%</span>
                    <div className="flex space-x-0.5 mb-1">
                        {[...Array(5)].map((_, i) => (
                            <div
                                key={i}
                                className={`w-1 h-3 ${i < Math.ceil(data.current_metrics.db_load / 20) ? 'bg-white' : 'bg-gray-800'}`}
                            />
                        ))}
                    </div>
                </div>
            </div>

            <div className="flex flex-col border-t border-gray-900 pt-6">
                <span className="nothing-text-label mb-1 text-[#FF3B30]">Cost Optimization</span>
                <div className="flex items-baseline space-x-2">
                    <span className="nothing-text-value text-white">${data.current_metrics.cost_savings_usd.toLocaleString()}</span>
                    <span className="text-[10px] text-gray-700">USD</span>
                </div>
                <div className="mt-3 w-full bg-gray-950 h-[1px]">
                    <div
                        className="bg-white h-[1px] shadow-[0_0_8px_white]"
                        style={{ width: '65%' }}
                    />
                </div>
            </div>
        </div>
    );
};

export default DashboardOverview;
